// Basic query
public async Task<IEnumerable<OrderDto>> GetOrdersAsync(string status, CancellationToken ct)
{
    await using var conn = await _factory.OpenConnectionAsync(ct);
    return await conn.QueryAsync<OrderDto>(
        "SELECT id, status, total, created_at FROM orders WHERE status = @Status",
        new { Status = status });
}

// Multi-mapping: JOIN với split mapping
var orders = await conn.QueryAsync<Order, Customer, Order>(
    "SELECT o.*, c.id, c.name FROM orders o JOIN customers c ON o.customer_id = c.id",
    (order, customer) => { order.Customer = customer; return order; },
    splitOn: "id");

// QueryMultiple: nhiều result set trong 1 roundtrip
using var multi = await conn.QueryMultipleAsync(
    "SELECT COUNT(*) FROM orders WHERE status=@s; SELECT * FROM orders WHERE status=@s LIMIT 20",
    new { s = status });
var total = await multi.ReadSingleAsync<int>();
var items = await multi.ReadAsync<OrderDto>();

// Stored procedure
